SELECT 
FROM acceptance_task t
LEFT JOIN project p ON p.id = t.project_id AND p.deleted = 0
LEFT JOIN acceptance_standard s ON s.id = t.standard_id AND s.deleted = 0

    t.deleted = 0

        AND t.project_id = #{query.projectId}


        AND t.name LIKE CONCAT('%', #{query.name}, '%')


        AND t.status = #{query.status}


        AND t.apply_user_id = #{query.applyUserId}


ORDER BY t.create_time DESC
